// Export functions for compatibility
export const getUnknownProductsByCategory = (category: string): Product[] => {
  if (category === 'All Products') return unknownScrapedProducts;
  return unknownScrapedProducts.filter(p => p.category === category);
};

export default unknownScrapedProducts;
